css:
.print-leave {
  font-size: 13px;
}
.print-leave table {
  width: 100%;
  border-collapse: collapse;
  table-layout: fixed;
}
.print-leave td, .print-leave th {
  border: 1px solid #333;
  padding: 6px 8px;
  vertical-align: top;
}
.print-leave .no-border { border: 0 !important; }
.print-leave .right { text-align: right; }
.print-leave .center { text-align: center; }
.print-leave .signature {
  height: 120px;
}
.print-leave .muted {
  color: #444;
}
.center {
  text-align: center;
  white-space: nowrap;
}
